private class CustomGLSurfaceView(context: Context) : GLSurfaceView(context) {
    var onSizeChangedCallback: ((Int, Int) -> Unit)? = null

    override fun onSizeChanged(w: Int, h: Int, oldw: Int, oldh: Int) {
        super.onSizeChanged(w, h, oldw, oldh)
        onSizeChangedCallback?.invoke(w, h)
    }
}

@Composable
fun ThermogramsAceScreen3(
    navController: NavHostController,
    viewModel: ThermogramAceViewModel = hiltViewModel()
) {

    LaunchedEffect(navController) { /* no-op: keep navController referenced for now */ }

    // snapshot counter local state
    var snapshotCount by remember { mutableStateOf(0) }

    // Toggle states for toolbar buttons
    var isThermalMode by remember { mutableStateOf(true) }
    var isFlashOn by remember { mutableStateOf(false) }
    var isLaserOn by remember { mutableStateOf(false) }
    var measurementSquareState by remember {
        mutableStateOf(ThermogramAceViewModel.MeasurementSquareState())
    }
    var measurementOverlaySize by remember { mutableStateOf(IntSize.Zero) }

    val snackbarHostState = remember { SnackbarHostState() }
    val scope = rememberCoroutineScope()

    var tempRange by remember { mutableStateOf(viewModel.getTemperatureRange()) }

    LaunchedEffect(Unit) {
        while (true) {
            tempRange = viewModel.getTemperatureRange()
            delay(500)
        }
    }

    BoxWithConstraints(
        modifier = Modifier
            .fillMaxSize()
            .background(Color.White)
    ) {
        val temperatureBarWidth = (maxWidth * 0.038f).coerceIn(14.dp, 18.dp)
        val temperatureBarHeight = (maxHeight * 0.68f).coerceIn(300.dp, 460.dp)
        val temperatureLabelShape = MaterialTheme.shapes.small

        // GLSurfaceView with renderer
        AndroidView(
            factory = { context: Context ->
                CustomGLSurfaceView(context).apply {
                    setEGLContextClientVersion(3)
                    preserveEGLContextOnPause = false
                    onSizeChangedCallback = { w: Int, h: Int ->
                        viewModel.onSurfaceSizeChanged(w, h)
                    }
                    viewModel.attachGlSurface(this)
                    viewModel.start()
//                    viewModel.startStream()
                }
            },
            modifier = Modifier
                .fillMaxSize()
                .background(color = Color.White)
        )

        val measurementModeBottomPadding = 176.dp

        Box(
            modifier = Modifier
                .fillMaxSize()
                .padding(bottom = measurementModeBottomPadding)
                .onSizeChanged { measurementOverlaySize = it }
        ) {
            if (measurementSquareState.enabled && measurementOverlaySize.width > 0 && measurementOverlaySize.height > 0) {
                val squareSizePx = (minOf(measurementOverlaySize.width, measurementOverlaySize.height) * measurementSquareState.sizeFraction)
                    .roundToInt()
                    .coerceAtLeast(24)
                val halfSquarePx = squareSizePx / 2
                val centerX = (measurementSquareState.centerXFraction * measurementOverlaySize.width).roundToInt()
                val centerY = (measurementSquareState.centerYFraction * measurementOverlaySize.height).roundToInt()
                val left = (centerX - halfSquarePx).coerceIn(0, (measurementOverlaySize.width - squareSizePx).coerceAtLeast(0))
                val top = (centerY - halfSquarePx).coerceIn(0, (measurementOverlaySize.height - squareSizePx).coerceAtLeast(0))

                Column(
                    modifier = Modifier
                        .offset { IntOffset(left, top) }
                        .wrapContentSize(),
                    horizontalAlignment = Alignment.CenterHorizontally
                )
                {
                    Box(
                        modifier = Modifier
                            .size(with(androidx.compose.ui.platform.LocalDensity.current) { squareSizePx.toDp() })
//                            .background(Color(0x33FFFFFF))
                            .border(2.dp, Color.White)
                            .pointerInput(measurementOverlaySize, measurementSquareState.enabled, measurementSquareState.sizeFraction) {
                                detectDragGestures { _, dragAmount ->
                                    val width = measurementOverlaySize.width.toFloat().coerceAtLeast(1f)
                                    val height = measurementOverlaySize.height.toFloat().coerceAtLeast(1f)
                                    val newCenterX = ((measurementSquareState.centerXFraction * width) + dragAmount.x)
                                        .coerceIn(halfSquarePx.toFloat(), width - halfSquarePx.toFloat())
                                    val newCenterY = ((measurementSquareState.centerYFraction * height) + dragAmount.y)
                                        .coerceIn(halfSquarePx.toFloat(), height - halfSquarePx.toFloat())

                                    measurementSquareState = measurementSquareState.copy(
                                        centerXFraction = newCenterX / width,
                                        centerYFraction = newCenterY / height
                                    )
                                    viewModel.setMeasurementSquareState(measurementSquareState)
                                }
                            }
                    )

                    Spacer(modifier = Modifier.height(4.dp))

                    Surface(
                        color = Color(0xCC000000),
                        shape = MaterialTheme.shapes.large,
                        modifier = Modifier.border(1.dp, Color.White, MaterialTheme.shapes.large)
                    ) {
                        Text(
                            text = "Bx1",
                            color = Color.White,
                            style = MaterialTheme.typography.labelLarge,
                            modifier = Modifier.padding(horizontal = 6.dp, vertical = 2.dp)
                        )
                    }
                }
            }
        }

        Box(
            modifier = Modifier
                .fillMaxSize()
                .padding(end = 2.dp,top = 8.dp),
            contentAlignment = Alignment.TopEnd
        ) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(end = 4.dp),
                horizontalAlignment = Alignment.End

            ) {
                val maxText = tempRange?.max?.let { String.format(Locale.getDefault(), "%.1f", it) } ?: "--"
                val minText = tempRange?.min?.let { String.format(Locale.getDefault(), "%.1f", it) } ?: "--"

                Surface(
                    color = Color(0xB0000000),
                    shape = temperatureLabelShape,
                    modifier = Modifier.border(1.dp, Color.White, temperatureLabelShape)
                ) {
                    Text(
                        text = maxText,
                        color = Color.White,
                        style = MaterialTheme.typography.labelLarge,
                        modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp)
                    )
                }

                Spacer(modifier = Modifier.height(6.dp))

                Box(
                    modifier = Modifier
                        .width(temperatureBarWidth)
                        .height(temperatureBarHeight)
                        .clip(temperatureLabelShape)
                        .border(1.dp, Color.White, temperatureLabelShape)
                        .background(
                            Brush.verticalGradient(
                                colors = listOf(
                                    Color(0xFFFFF6C2), // quase branco (topo)
                                    Color(0xFFFFE066), // amarelo claro
                                    Color(0xFFFFB347), // amarelo/laranja
                                    Color(0xFFFF7A1A), // laranja forte
                                    Color(0xFFE53935), // vermelho
                                    Color(0xFF8E24AA), // roxo
                                    Color(0xFF3949AB), // azul
                                    Color(0xFF0D1B2A)  // azul escuro (base)
                                )
                            )
                        )
                ) {
                }

                Spacer(modifier = Modifier.height(6.dp))

                Surface(
                    color = Color(0xB0000000),
                    shape = temperatureLabelShape,
                    modifier = Modifier.border(1.dp, Color.White, temperatureLabelShape)
                ) {
                    Text(
                        text = minText,
                        color = Color.White,
                        style = MaterialTheme.typography.labelLarge,
                        modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp)
                    )
                }

                Spacer(modifier = Modifier.height(8.dp))

                Surface(
                    color = Color(0xCC000000),
                    shape = CircleShape,
                    modifier = Modifier.border(1.dp, Color.White, CircleShape)
                ) {
                    IconButton(
                        onClick = { /* placeholder only: configure min/max later */ },
                        modifier = Modifier.size(34.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Filled.Tune,
                            contentDescription = "Configure temperature range",
                            tint = Color.White,
                            modifier = Modifier.size(18.dp)
                        )
                    }
                }
            }
        }

        // Stop stream and disconnect when leaving the screen
        DisposableEffect(Unit) {
            onDispose {
                viewModel.stop()
            }
        }

        // Snackbar host
        Box(modifier = Modifier.fillMaxSize()) {
            SnackbarHost(
                hostState = snackbarHostState,
                modifier = Modifier
                    .align(Alignment.TopCenter)
                    .statusBarsPadding()
            )
        }

        Box(
            modifier = Modifier.fillMaxSize(),
            contentAlignment = Alignment.BottomCenter
        ) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .wrapContentHeight()
                    .navigationBarsPadding(),
                verticalArrangement = Arrangement.Bottom,
                horizontalAlignment = Alignment.CenterHorizontally
            ) {
                Spacer(modifier = Modifier.height(12.dp))

                Box(contentAlignment = Alignment.Center) {
                    if (snapshotCount > 0) {
                        Surface(
                            shape = CircleShape,
                            color = Color(0x99000000),
                            tonalElevation = 2.dp,
                            modifier = Modifier
                                .align(Alignment.TopCenter)
                                .offset(y = (-36).dp)
                        ) {
                            Text(
                                text = snapshotCount.toString(),
                                color = Color.White,
                                modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp)
                            )
                        }
                    }

                    Box(
                        contentAlignment = Alignment.Center,
                        modifier = Modifier
                            .size(50.dp)
                            .clip(CircleShape)
                            .background(Color.Black)
                            .border(width = 2.dp, color = Color.LightGray, shape = CircleShape)
                    ) {
                        IconButton(onClick = {
                            viewModel.takeSnapshot { success, msg, _ ->
                                scope.launch {
                                    if (success) {
                                        snapshotCount++
                                        snackbarHostState.showSnackbar("Snapshot saved")
                                    } else {
                                        snackbarHostState.showSnackbar("Snapshot failed: ${msg ?: "unknown"}")
                                    }
                                }
                            }
                        }) {
                            Icon(
                                imageVector = Icons.Filled.Camera,
                                contentDescription = "Snapshot",
                                tint = Color.White,
                                modifier = Modifier.size(50.dp)
                            )
                        }
                    }
                }

                Spacer(modifier = Modifier.height(12.dp))

                Surface(
                    tonalElevation = 8.dp,
                    color = MaterialTheme.colorScheme.surface.copy(alpha = 0.95f),
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(72.dp)
                ) {
                    Row(
                        modifier = Modifier
                            .fillMaxSize()
                            .padding(horizontal = 8.dp),
                        horizontalArrangement = Arrangement.SpaceEvenly,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        IconButton(onClick = { isThermalMode = !isThermalMode }) {
                            Icon(
                                imageVector = Icons.Filled.CameraAlt,
                                contentDescription = "Toggle camera view",
                                tint = if (isThermalMode) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurface
                            )
                        }

                        IconButton(onClick = {
                            measurementSquareState = measurementSquareState.copy(
                                enabled = !measurementSquareState.enabled,
                                centerXFraction = 0.5f,
                                centerYFraction = 0.5f
                            )
                            viewModel.setMeasurementSquareState(measurementSquareState)
                        }) {
                            Icon(
                                imageVector = Icons.Default.CenterFocusStrong,
                                contentDescription = "Measurement tools",
                                tint = if (measurementSquareState.enabled) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurface
                            )
                        }

                        IconButton(onClick = { /* palette selector */ }) {
                            Icon(
                                imageVector = Icons.Filled.ColorLens,
                                contentDescription = "Palette",
                                tint = MaterialTheme.colorScheme.onSurface
                            )
                        }

                        IconButton(onClick = {
                            viewModel.toggleFlash { success, msg ->
                                if (!success)
                                    scope.launch { snackbarHostState.showSnackbar("Flash failed: $msg") }
                                else
                                    isFlashOn = !isFlashOn
                            }
                        }) {
                            Icon(
                                imageVector = Icons.Filled.FlashOn,
                                contentDescription = "Flashlight",
                                tint = if (isFlashOn) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurface
                            )
                        }

                        IconButton(onClick = {
                            viewModel.toggleLaser { success, msg ->
                                if (!success)
                                    scope.launch { snackbarHostState.showSnackbar("Laser failed: $msg") }
                                else
                                    isLaserOn = !isLaserOn
                            }
                        }) {
                            Icon(
                                imageVector = Icons.Filled.GpsFixed,
                                contentDescription = "Laser",
                                tint = if (isLaserOn) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurface
                            )
                        }
                    }
                }
            }
        }
    }
}

package com.tech.thermography.android.ui.camera

import android.content.Context
